// Auto-generated script: extracts chain data from @wcore/core for /dev/deploy
// Run via: npx tsx scripts/extract-deploy-chain-data.mjs
import { chains } from "../packages/core/src/index.ts";
import { readFileSync, writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";

const __dirname = dirname(fileURLToPath(import.meta.url));
const deployClientPath = resolve(__dirname, "../apps/web/app/dev/deploy/DeployClient.tsx");
const src = readFileSync(deployClientPath, "utf8");
const m = src.match(/const DEPLOY_CHAIN_KEYS = \[([\s\S]*?)\] as const/);
if (!m) throw new Error("DEPLOY_CHAIN_KEYS not found");
const keys = [...m[1].matchAll(/"([A-Z_0-9]+)"/g)].map((x) => x[1]);

const out = ["// AUTO-GENERATED by scripts/extract-deploy-chain-data.mjs — do not edit by hand."];
out.push("// Source: packages/core/src/chains/*.ts (built-time extract).");
out.push("// Regenerate when chain data changes: npx tsx scripts/extract-deploy-chain-data.mjs");
out.push("");
out.push('import type { AddEthereumChainParams } from "./chain-params";');
out.push("");
out.push("/**");
out.push(" * Inline chain params for `wallet_addEthereumChain` fallback when MetaMask");
out.push(" * does not know the target chain. Duplicated from @wcore/core (per AGENTS.md gotcha:");
out.push(" * do not import @wcore/core at runtime from web frontend).");
out.push(" */");
out.push("export const DEPLOY_CHAIN_PARAMS: Record<string, AddEthereumChainParams> = {");
for (const key of keys) {
  const c = chains[key];
  if (!c?.CHAIN?.CHAIN_ID || !c?.RPC?.ENDPOINTS?.length) {
    console.warn(`SKIP ${key}: missing CHAIN_ID or RPC.ENDPOINTS`);
    continue;
  }
  const chainId = c.CHAIN.CHAIN_ID;
  const name = c.CHAIN.NAME ?? key;
  const sym = c.CHAIN.NATIVE_SYMBOL ?? "ETH";
  const nname = c.CHAIN.NATIVE_NAME ?? sym;
  const dec = c.CHAIN.NATIVE_DECIMALS ?? 18;
  const rpcs = c.RPC.ENDPOINTS.map((r) => `"${r.replace(/"/g, '\\"')}"`).join(", ");
  out.push(`  ${key}: {`);
  out.push(`    chainId: "0x${chainId.toString(16)}",`);
  out.push(`    chainName: ${JSON.stringify(name)},`);
  out.push(`    nativeCurrency: { name: ${JSON.stringify(nname)}, symbol: ${JSON.stringify(sym)}, decimals: ${dec} },`);
  out.push(`    rpcUrls: [${rpcs}],`);
  out.push(`  },`);
}
out.push("};");
out.push("");
out.push("/** Numeric chainIds we support, derived from DEPLOY_CHAIN_PARAMS keys. */");
out.push("export const SUPPORTED_CHAIN_IDS: Set<number> = new Set([");
for (const key of keys) {
  const c = chains[key];
  if (c?.CHAIN?.CHAIN_ID) out.push(`  ${c.CHAIN.CHAIN_ID}, // ${key}`);
}
out.push("]);");

const target = resolve(__dirname, "../apps/web/app/dev/deploy/chain-data.ts");
writeFileSync(target, out.join("\n") + "\n", "utf8");
console.log(`Wrote ${target}`);
console.log(`Total chains: ${keys.length}, with data: ${out.filter((l) => l.startsWith("  ")).length / 5 | 0}`);
